{
  "name": "My Custom Trading Strategy",
  "description": "A simple RSI-based mean reversion strategy",
  "category": "mean_reversion",
  "rules": [
    {
      "name": "Buy on RSI Oversold",
      "conditions": [
        {
          "indicator": "rsi",
          "operator": "<",
          "value": 30,
          "params": {
            "period": 14
          },
          "timeframe": "1h"
        }
      ],
      "logicalOperator": "AND",
      "action": {
        "type": "buy",
        "quantity": "half",
        "stopLoss": 5,
        "takeProfit": 10
      },
      "priority": 1,
      "isActive": true
    },
    {
      "name": "Sell on RSI Overbought",
      "conditions": [
        {
          "indicator": "rsi",
          "operator": ">",
          "value": 70,
          "params": {
            "period": 14
          },
          "timeframe": "1h"
        }
      ],
      "logicalOperator": "AND",
      "action": {
        "type": "sell",
        "quantity": "all"
      },
      "priority": 2,
      "isActive": true
    }
  ],
  "riskManagement": {
    "maxPositionSize": 20,
    "maxDailyLoss": 5,
    "stopLossEnabled": true,
    "takeProfitEnabled": true
  },
  "tags": ["rsi", "mean-reversion", "custom"]
}

