      "conditions": [
        {
          "indicator": "sma",
          "operator": "crosses_above",
          "value": {
            "indicator": "sma",
            "params": {
              "period": 50
            }
          },
          "params": {
            "period": 20
          },
          "timeframe": "1d"
        }
      ],
      "logicalOperator": "AND",
      "action": {
        "type": "buy",
        "quantity": "half",
        "stopLoss": 5,
        "takeProfit": 10
