    {
      "name": "Sell Signal - SMA Crossover",
      "conditions": [
        {
          "indicator": "sma",
          "operator": "crosses_below",
          "value": {
            "indicator": "sma",
            "params": {
              "period": 50
            }
          },
          "params": {
            "period": 20
          },
          "timeframe": "1d"
        }
      ],
      "logicalOperator": "AND",
      "action": {
        "type": "sell",
        "quantity": "all"
      },
      "priority": 2,
