    "maxDailyLoss": 3,
    "stopLossEnabled": true,
    "takeProfitEnabled": true
  },
  "tags": ["sma", "crossover", "trend-following"]
}

{
  "name": "MACD Momentum Strategy",
  "description": "Buy when MACD line crosses above signal line, sell when it crosses below",
  "category": "momentum",
  "rules": [
    {
      "name": "MACD Bullish Cross",
      "conditions": [
        {
          "indicator": "macd",
          "operator": "crosses_above",
          "value": {
            "indicator": "macd",
            "line": "signal"
          },
          "params": {
            "fast": 12,
            "slow": 26,
            "signal": 9
          },
          "timeframe": "1d"
        },
        {
          "indicator": "macd",
          "operator": ">",
          "value": 0,
          "params": {
            "fast": 12,
            "slow": 26,
            "signal": 9
          },
          "timeframe": "1d"
        }
      ],
      "logicalOperator": "AND",
      "action": {
        "type": "buy",
        "quantity": "half",
        "stopLoss": 3,
        "takeProfit": 9
      },
      "priority": 1,
      "isActive": true
    },
    {
      "name": "MACD Bearish Cross",
      "conditions": [
        {
          "indicator": "macd",
          "operator": "crosses_below",
          "value": {
            "indicator": "macd",
            "line": "signal"
          },
          "params": {
            "fast": 12,
            "slow": 26,
            "signal": 9
          },
          "timeframe": "1d"
        }
      ],
      "logicalOperator": "AND",
      "action": {
        "type": "sell",
        "quantity": "all"
      },
      "priority": 2,
      "isActive": true
    }
  ],
  "riskManagement": {
    "maxPositionSize": 18,
    "maxDailyLoss": 3,
    "stopLossEnabled": true,
    "takeProfitEnabled": true
  },
  "tags": ["macd", "momentum", "crossover"]
}

{
  "name": "Multi-Indicator Confirmation Strategy",
  "description": "Conservative strategy requiring multiple indicators to align before trading",
  "category": "trend_following",
  "rules": [
    {
      "name": "Multi-Signal Buy",
      "conditions": [
        {
          "indicator": "price",
          "operator": ">",
          "value": {
            "indicator": "sma",
            "params": {
              "period": 50
            }
          },
          "timeframe": "1d"
        },
        {
          "indicator": "rsi",
          "operator": ">",
          "value": 50,
          "params": {
            "period": 14
          },
          "timeframe": "1d"
        },
        {
          "indicator": "macd",
          "operator": ">",
          "value": {
            "indicator": "macd",
            "line": "signal"
          },
          "params": {
            "fast": 12,
            "slow": 26,
            "signal": 9
          },
          "timeframe": "1d"
        }
      ],
      "logicalOperator": "AND",
      "action": {
        "type": "buy",
        "quantity": "custom",
        "customQuantity": 500,
        "stopLoss": 5,
        "takeProfit": 12
      },
      "priority": 1,
      "isActive": true
    },
    {
      "name": "Multi-Signal Sell",
      "conditions": [
        {
          "indicator": "price",
          "operator": "<",
          "value": {
            "indicator": "sma",
            "params": {
              "period": 20
            }
          },
          "timeframe": "1d"
        },
        {
          "indicator": "rsi",
          "operator": "<",
          "value": 45,
          "params": {
            "period": 14
          },
          "timeframe": "1d"
        }
      ],
      "logicalOperator": "OR",
      "action": {
        "type": "sell",
        "quantity": "all"
      },
      "priority": 2,
      "isActive": true
    }
  ],
  "riskManagement": {
    "maxPositionSize": 12,
    "maxDailyLoss": 2,
    "stopLossEnabled": true,
    "takeProfitEnabled": true
  },
  "tags": ["multi-indicator", "conservative", "confirmation"]
}

